import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { Dependent } from '../../../core/models';

/** Wizard step 2 — add/remove dependents (age drives child tax credit). */
@Component({
  selector: 'app-dependents',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './dependents.component.html',
  styleUrl: './dependents.component.css',
})
export class DependentsComponent {
  returnId = '';

  // Mock data — service_agent clears this and loads via ApiService.listDependents().
  dependents = signal<Dependent[]>([
    { id: 'd1', returnId: 'r-2024', name: 'Riley Filer', age: 9 },
  ]);

  newName = '';
  newAge: number | null = null;

  constructor(private route: ActivatedRoute, private router: Router) {
    this.returnId = this.route.parent?.snapshot.paramMap.get('id') ?? '';
  }

  add(): void {
    if (!this.newName || this.newAge === null) return;
    this.dependents.update((list) => [
      ...list,
      {
        id: 'd' + (list.length + 1) + '-' + this.newAge,
        returnId: this.returnId,
        name: this.newName,
        age: Number(this.newAge),
      },
    ]);
    this.newName = '';
    this.newAge = null;
  }

  remove(id: string): void {
    this.dependents.update((list) => list.filter((d) => d.id !== id));
  }

  back(): void {
    this.router.navigate(['/returns', this.returnId, 'wizard', 'filing-status']);
  }

  next(): void {
    this.router.navigate(['/returns', this.returnId, 'wizard', 'income']);
  }
}
